INSERT INTO `Suppliers` (`BankAccount`, `BankID`, `CityID`, `CompanyEmail`, `CompanyTelephone`, `ContactEmail`, `ContactFirstName`, `ContactLastName`, `ContactMiddleName`, `ContactTelephone`, `DirectorFirstName`, `DirectorLastName`, `DirectorMiddleName`, `LegalCode`, `Name`, `NegativeRemarks`, `PostalIndex`, `SpecializationID`, `StreetBuilding`)
VALUES (@p0, @p1, @p2, @p3, @p4, @p5, @p6, @p7, @p8, @p9, @p10, @p11, @p12, @p13, @p14, @p15, @p16, @p17, @p18);
SELECT `ID`
FROM `Suppliers`
WHERE ROW_COUNT() = 1
 AND `ID`=LAST_INSERT_ID();
